const os = require('os');
const fs = require('fs');
const path = require('path');

const filePath = path.join(__dirname, 'system-info.json');

const newReport = {
  timestamp: new Date().toISOString(),
  platform: os.platform(),
  arch: os.arch(),
  cpuCount: os.cpus().length,
  totalMemoryGB: (os.totalmem() / 1e9).toFixed(2),
  freeMemoryGB: (os.freemem() / 1e9).toFixed(2),
  uptimeHours: (os.uptime() / 3600).toFixed(2)
};

fs.readFile(filePath, 'utf8', (err, data) => {
  let reports = [];
  if (!err && data) {
    try {
      reports = JSON.parse(data);
    } catch (e) {
      console.error('Invalid JSON, starting fresh.');
    }
  }
  reports.push(newReport);
  fs.writeFile(filePath, JSON.stringify(reports, null, 2), (err) => {
    if (err) console.error('Error writing file:', err);
    else console.log('Report added.');
  });
});
